class Solution(object):
    def longestBalanced(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        from collections import defaultdict

        n = len(nums)

        # Precompute first occurrence of each value
        first_occ = {}
        for i, num in enumerate(nums):
            if num not in first_occ:
                first_occ[num] = i

        # For each value, compute next occurrences
        next_occ = defaultdict(list)
        for i, num in enumerate(nums):
            next_occ[num].append(i)

        max_len = 0

        # Try all starting positions
        for l in range(n):
            # Count distinct even and odd in current window
            even_count = 0
            odd_count = 0
            even_set = set()
            odd_set = set()

            for r in range(l, n):
                num = nums[r]
                if num % 2 == 0:
                    if num not in even_set:
                        even_set.add(num)
                        even_count += 1
                else:
                    if num not in odd_set:
                        odd_set.add(num)
                        odd_count += 1

                # Check if balanced
                if even_count == odd_count:
                    max_len = max(max_len, r - l + 1)

        return max_len
